INSERT INTO subject_content_status_backups ( subject_id, content_type, content_id, was_active ) SELECT #{subjectId}, source.content_type, source.content_id, source.was_active FROM ( SELECT 'CURRICULUM' AS content_type, cn.node_id AS content_id, cn.is_active AS was_active FROM curriculum_nodes cn WHERE cn.subject_id = #{subjectId}
UNION ALL
SELECT 'LESSON' AS content_type, l.lesson_id AS content_id, l.is_active AS was_active FROM lessons l INNER JOIN curriculum_nodes cn ON cn.node_id = l.node_id WHERE cn.subject_id = #{subjectId}
UNION ALL
SELECT 'PROBLEM' AS content_type, pp.problem_id AS content_id, pp.is_active AS was_active FROM practice_problems pp WHERE pp.subject_id = #{subjectId} ) source ON DUPLICATE KEY UPDATE was_active = VALUES(was_active), created_at = NOW()
